  ('aboriginal-c5fb3965-moex-00094', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-bdc7da1c', 'sub-aboriginal-c5fb3965-02', NULL, 'single_choice', '25歲之甲為取得法國國籍，經內政部許可喪失我國國籍。假設甲嗣後未順利取得法國國籍，內政部應如何 處理？', '["依甲之申請回復其國籍", "依甲之申請撤銷國籍之喪失", "命其依無國籍人之規定申請歸化", "主動依職權回復甲之國籍"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "ec1e235b5965", "answer_pdf_sha1": "c1e439afad77", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0612", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
